import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS Vulnerability')</script>";
        String sanitizedInput = Encode.forHtml(userInput);

        // Properly handling user input by sanitizing it before outputting
        PrintWriter out = new PrintWriter("index.html");
        out.println("<html>");
        out.println("<head><title>XSS Vulnerability Demo</title></head>");
        out.println("<body>");
        out.println("<h1>Welcome " + sanitizedInput + "</h1>");
        out.println("</body>");
        out.println("</html>");

        out.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
